  "helpers": [
    {
      "label": "correspondence_mapper",
      "instructions": "Identify and describe the three specific formal mathematical correspondences between Quantum Darwinism (the process of environment-induced decoherence and information redundancy) and Holographic Quantum Error Correction (the encoding of bulk information into boundary entanglement). Focus on how redundancy in the environment relates to the code subspace and how subsystem information relates to the bulk-boundary mapping."
    },
    {
      "label": "citation_gap_analyst",
      "instructions": "Search for existing literature that explicitly links Quantum Darwinism and Holographic QEC. Specifically, identify if there is a known 'gap' or a missing formal proof that connects the redundancy of information in the environment to the error-correcting properties of the AdS/CFT bulk-boundary mapping. Determine if the relationship is currently considered an analogy or a proven formal equivalence."
    }
  ],
  "synthesis_brief": "Combine the three mathematical correspondences identified by the mapper with the literature findings from the analyst. The final answer must state whether a formal relationship exists, detail the three correspondences, and explicitly address the citation-gap (whether the link is established or remains a conjecture/analogy)."
}

